/**
 * Cortical surface point cloud for the hero brain.
 *
 * 6,000 area-weighted points (with surface normals) sampled from a real
 * FreeSurfer pial cortical surface — so the gyri, sulci, central fissure and
 * lobes are genuine anatomy, not procedural. int8-quantised, base64-packed.
 *
 * Source mesh: brainder.org "Brain for Blender" pial surface
 * (Anderson M. Winkler), CC-BY-SA 3.0. See the site colophon for attribution.
 * (Swappable for the CC0 NIH glassbrain to drop the attribution requirement.)
 */
export const PIAL_N = 6000

export type Cloud = {
  x: Float32Array; y: Float32Array; z: Float32Array
  nx: Float32Array; ny: Float32Array; nz: Float32Array
}

const B64 = ''

/** Decode the packed cloud (positions + normals), centred and normalised to max extent 1. */
export function decodePial(): Cloud {
  const bin = atob(B64)
  const n = PIAL_N
  const c: Cloud = {
    x: new Float32Array(n), y: new Float32Array(n), z: new Float32Array(n),
    nx: new Float32Array(n), ny: new Float32Array(n), nz: new Float32Array(n),
  }
  const s = (o: number) => ((bin.charCodeAt(o) & 255) << 24 >> 24) / 127
  for (let i = 0; i < n; i++) {
    const o = i * 6
    c.x[i] = s(o); c.y[i] = s(o + 1); c.z[i] = s(o + 2)
    c.nx[i] = s(o + 3); c.ny[i] = s(o + 4); c.nz[i] = s(o + 5)
  }
  return c
}

/** Even point distribution on a unit sphere (morph source). */
export function fibonacciSphere(n: number) {
  const x = new Float32Array(n), y = new Float32Array(n), z = new Float32Array(n)
  const GA = Math.PI * (3 - Math.sqrt(5))
  for (let i = 0; i < n; i++) {
    const yy = 1 - ((i + 0.5) / n) * 2
    const r = Math.sqrt(Math.max(0, 1 - yy * yy))
    const th = GA * i
    x[i] = Math.cos(th) * r; y[i] = yy; z[i] = Math.sin(th) * r
  }
  return { x, y, z }
}

/**
 * Surface-following "fold lines": link points that are close in 3D AND share a
 * surface normal (same fold) — so edges trace along the gyri rather than forming
 * a nearest-neighbour constellation web. Built once.
 */
export function buildFoldEdges(P: Cloud): { a: Int32Array; b: Int32Array } {
  const A: number[] = [], B: number[] = []
  const CELL = 0.08, R2 = 0.078 * 0.078
  const grid = new Map<string, number[]>()
  const key = (a: number, b: number, c: number) => a + '_' + b + '_' + c
  for (let i = 0; i < PIAL_N; i++) {
    const k = key(Math.floor(P.x[i] / CELL), Math.floor(P.y[i] / CELL), Math.floor(P.z[i] / CELL))
    let arr = grid.get(k); if (!arr) { arr = []; grid.set(k, arr) }
    arr.push(i)
  }
  for (let i = 0; i < PIAL_N; i++) {
    const gx = Math.floor(P.x[i] / CELL), gy = Math.floor(P.y[i] / CELL), gz = Math.floor(P.z[i] / CELL)
    let cnt = 0
    for (let a = -1; a <= 1 && cnt < 2; a++) for (let b = -1; b <= 1 && cnt < 2; b++) for (let c = -1; c <= 1 && cnt < 2; c++) {
      const arr = grid.get(key(gx + a, gy + b, gz + c)); if (!arr) continue
      for (let t = 0; t < arr.length; t++) {
        const j = arr[t]; if (j <= i) continue
        const dx = P.x[i] - P.x[j], dy = P.y[i] - P.y[j], dz = P.z[i] - P.z[j]
        const d2 = dx * dx + dy * dy + dz * dz; if (d2 > R2 || d2 < 1e-6) continue
        const nd = P.nx[i] * P.nx[j] + P.ny[i] * P.ny[j] + P.nz[i] * P.nz[j]; if (nd < 0.55) continue
        A.push(i); B.push(j); cnt++; if (cnt >= 2) break
      }
    }
  }
  return { a: Int32Array.from(A), b: Int32Array.from(B) }
}
